import{_ as o,o as t,c as a,ag as r}from"./chunks/framework.1N8rnUr9.js";const p=JSON.parse('{"title":"Shortcodes","description":"","frontmatter":{},"headers":[],"relativePath":"features/shortcodes.md","filePath":"features/shortcodes.md","lastUpdated":1775898496000}'),s={name:"features/shortcodes.md"};function i(d,e,l,n,h,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="shortcodes" tabindex="-1">Shortcodes <a class="header-anchor" href="#shortcodes" aria-label="Permalink to &quot;Shortcodes&quot;">​</a></h1><p>While TubeBay handles video placement automatically based on your settings, you often need more control for specific page layouts or landing pages. Our shortcodes allow you to embed videos anywhere that supports WordPress shortcodes.</p><h2 id="the-global-video-shortcode" tabindex="-1">The Global Video Shortcode <a class="header-anchor" href="#the-global-video-shortcode" aria-label="Permalink to &quot;The Global Video Shortcode&quot;">​</a></h2><p>TubeBay includes a powerful shortcode system that allows you to embed your YouTube videos anywhere on your WordPress site, not just on product pages.</p><h2 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h2><p>To embed a video, use the following shortcode structure:</p><p><code>[tubebay_video id=&quot;YOUTUBE_VIDEO_ID&quot;]</code></p><h3 id="how-to-get-the-video-id" tabindex="-1">How to get the Video ID? <a class="header-anchor" href="#how-to-get-the-video-id" aria-label="Permalink to &quot;How to get the Video ID?&quot;">​</a></h3><p>You can find the ID for any of your synced videos in the <strong>TubeBay &gt; Library</strong> tab.</p><h2 id="customizing-the-player" tabindex="-1">Customizing the Player <a class="header-anchor" href="#customizing-the-player" aria-label="Permalink to &quot;Customizing the Player&quot;">​</a></h2><p>You can pass various parameters to the shortcode to customize the look and feel of the player:</p><ul><li><strong>width</strong>: Set the width of the player (e.g., <code>800px</code> or <code>100%</code>).</li><li><strong>autoplay</strong>: Set to <code>true</code> to start the video immediately (Note: Browser policies may apply).</li><li><strong>controls</strong>: Set to <code>false</code> to hide YouTube player controls.</li></ul><p><strong>Example with parameters:</strong><code>[tubebay_video id=&quot;your_id&quot; width=&quot;100%&quot; autoplay=&quot;false&quot;]</code></p><h2 id="front-end-preview" tabindex="-1">Front-end Preview <a class="header-anchor" href="#front-end-preview" aria-label="Permalink to &quot;Front-end Preview&quot;">​</a></h2><p>When you place a shortcode in a page or post, it will render as a responsive, high-quality video player.</p><hr><h2 id="technical-performance" tabindex="-1">Technical Performance <a class="header-anchor" href="#technical-performance" aria-label="Permalink to &quot;Technical Performance&quot;">​</a></h2><ul><li><strong>Zero Impact on Page Speed:</strong> TubeBay uses lazy-loading for iframe elements. The actual YouTube player only loads when the user interacts with the thumbnail.</li><li><strong>Theme Independent:</strong> The shortcodes are designed to inherit your theme&#39;s container width while staying perfectly responsive.</li><li><strong>Gutenberg:</strong> Use the Shortcode or Custom HTML block.</li><li><strong>Beaver Builder:</strong> Use the HTML or Text module.</li></ul>',18)])])}const g=o(s,[["render",i]]);export{p as __pageData,g as default};
